// ===============================
// POBRANIE DANYCH Z CLICKUP
// ===============================

const fields = $json.custom_fields || [];

const getField = (name) => {
  return fields.find(f => f.name === name)?.value ?? null;
};

const getFieldById = (id) => {
  return fields.find(f => f.id === id)?.value ?? null;
};


// ===============================
// BEZPIECZNA FUNKCJA DATY
// ===============================

const formatDateSafe = (value) => {
  const today = new Date().toISOString().split('T')[0];

  if (!value) return today;

  if (!isNaN(value)) {
    return new Date(Number(value)).toISOString().split('T')[0];
  }

  if (typeof value === 'string' && value.includes('-')) {
    return value;
  }

  if (typeof value === 'string' && value.includes('/')) {
    const parts = value.split('/');
    return `${parts[2]}-${parts[1]}-${parts[0]}`;
  }

  return today;
};


// ===============================
// DATY
// ===============================

const issueDate = formatDateSafe(getField('Data wystawienia'));

const paymentDate = formatDateSafe(
  getFieldById('1abcd4d2-06e2-458f-b283-b8d5039720ad')
);

// ===============================
// WIELE POZYCJI – CZYTANIE PO ID
// ===============================

let positions = [];

const positionField = fields.find(
  f => f.id === '391f43f9-a4bc-435e-b9f1-16c273c4b98e'
);

let rawPositions = null;

if (positionField) {
  rawPositions = positionField.value || positionField.value_richtext || null;
}

// DEBUG – możesz chwilowo sprawdzić co przychodzi
// return [{ json: { rawPositions } }];

if (rawPositions && typeof rawPositions === 'string') {

  const cleanedText = rawPositions.replace(/<[^>]*>/g, '');
  const rows = cleanedText.split('\n');

  rows.forEach(row => {

    if (!row.trim()) return;

    const parts = row.split('|').map(p => p.trim());

    if (parts.length >= 4) {

      const name = parts[0] || "Usługa";
      const quantity = Number(parts[1]) > 0 ? Number(parts[1]) : 1;
      const totalPrice = Number(parts[2]) > 0 ? Number(parts[2]) : 0;

      let vatRaw = parts[3];
      let vat = 23;

      if (vatRaw.includes('%')) {
        vat = Number(vatRaw.replace('%', '').trim());
      } else if (!isNaN(vatRaw)) {
        vat = Number(vatRaw);
      }

      positions.push({
        name: name,
        quantity: quantity,
        total_price_gross: totalPrice,
        tax: vat
      });
    }

  });
}


// ===============================
// FALLBACK
// ===============================

if (positions.length === 0) {
  positions.push({
    name: "Usługa",
    quantity: 1,
    total_price_gross: 100,
    tax: 23
  });
}
// ===============================
// ZWRACAMY OBIEKT DLA FAKTUROWNI
// ===============================

return [
  {
    json: {
      invoice: {
        kind: "vat",
        status: "issued",

        issue_date: issueDate,
        sell_date: issueDate,
        payment_to: paymentDate,
        payment_type: "transfer",

        buyer_name: getField('Nazwa firmy') || "Brak nazwy",
        buyer_email: getField('email') || "brak@email.pl",
        buyer_tax_no: getField('NIP') || "0000000000",
        buyer_city: getField('Miasto') || "Miasto",
        buyer_post_code: getField('Kod pocztowy') || "00-000",

        positions: positions,

        description: "Zamówienie z formularza ClickUp"
      }
    }
  }
];

const output = [];

for (const item of items) {
  const fields = item.json.custom_fields || [];

  const reminderField = fields.find(f => f.name === 'Data przypomnienia');

  if (!reminderField?.value) continue;

  const reminderDate = new Date(Number(reminderField.value))
    .toISOString()
    .split('T')[0];

  const today = new Date().toISOString().split('T')[0];

  if (reminderDate === today) {
    output.push({
      json: item.json
    });
  }
}

return output;

